import React, { useState, useEffect } from 'react';
import './Calculator.css';

const EMICalculator = () => {
  const [inputs, setInputs] = useState({
    loanAmount: '',
    interestRate: '',
    tenure: '',
    monthlySalary: ''
  });
  const [results, setResults] = useState({});
  const [suggestion, setSuggestion] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('emiInputs');
    if (saved) {
      setInputs(JSON.parse(saved));
    }
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setInputs({ ...inputs, [name]: value });
  };

  const calculateEMI = () => {
    setLoading(true);
    setTimeout(() => {
      const P = parseFloat(inputs.loanAmount);
      const R = parseFloat(inputs.interestRate) / 100 / 12;
      const N = parseFloat(inputs.tenure) * 12;

      if (P && R && N) {
        const emi = (P * R * Math.pow(1 + R, N)) / (Math.pow(1 + R, N) - 1);
        const totalPayment = emi * N;
        const interestPaid = totalPayment - P;

        setResults({
          monthlyEMI: emi.toFixed(2),
          totalPayment: totalPayment.toFixed(2),
          interestPaid: interestPaid.toFixed(2)
        });

        // AI Suggestion
        const salary = parseFloat(inputs.monthlySalary);
        if (salary && emi > 0.4 * salary) {
          setSuggestion('⚠️ Your EMI is too high. Consider reducing loan amount.');
        } else {
          setSuggestion('✅ Your EMI is within safe limits.');
        }

        localStorage.setItem('emiInputs', JSON.stringify(inputs));
      }
      setLoading(false);
    }, 1000); // Simulate loading
  };

  const reset = () => {
    setInputs({
      loanAmount: '',
      interestRate: '',
      tenure: '',
      monthlySalary: ''
    });
    setResults({});
    setSuggestion('');
    localStorage.removeItem('emiInputs');
  };

  const generateReport = () => {
    alert(`EMI Report:\nMonthly EMI: ${results.monthlyEMI}\nTotal Payment: ${results.totalPayment}\nInterest Paid: ${results.interestPaid}`);
  };

  return (
    <div className="calculator">
      <h2>EMI Calculator</h2>
      <div className="inputs">
        <label>Loan Amount (₹)</label>
        <input type="number" name="loanAmount" value={inputs.loanAmount} onChange={handleInputChange} />

        <label>Interest Rate (% per annum)</label>
        <input type="number" name="interestRate" value={inputs.interestRate} onChange={handleInputChange} />

        <label>Tenure (years)</label>
        <input type="number" name="tenure" value={inputs.tenure} onChange={handleInputChange} />

        <label>Monthly Salary (₹) - for suggestion</label>
        <input type="number" name="monthlySalary" value={inputs.monthlySalary} onChange={handleInputChange} />
      </div>
      <div className="buttons">
        <button onClick={calculateEMI} disabled={loading}>Calculate</button>
        <button onClick={reset}>Reset</button>
        <button onClick={generateReport} disabled={!results.monthlyEMI}>Generate Report</button>
      </div>
      {loading && <div className="loading">Calculating...</div>}
      {results.monthlyEMI && (
        <div className="results">
          <h3>Results</h3>
          <p>Monthly EMI: ₹{results.monthlyEMI}</p>
          <p>Total Payment: ₹{results.totalPayment}</p>
          <p>Interest Paid: ₹{results.interestPaid}</p>
        </div>
      )}
      {suggestion && (
        <div className="suggestion">
          <p>{suggestion}</p>
        </div>
      )}
    </div>
  );
};

export default EMICalculator;
